const AWS = require('aws-sdk');
const s3 = new AWS.S3();
const destinationBucket = 'destination-bucket';

exports.handler = async (event) => {
  let srcBucket = event.Records[0].s3.bucket.name;

  // Get the object key
  let srcKey = decodeURIComponent(
    event.Records[0].s3.object.key.replace(/\+/g, " ")
  );

  // Retrieve the object from S3
  let params = {
    Bucket: srcBucket,
    Key: srcKey
  };

  let inputData = await s3.getObject(params).promise();

  // TODO: add your processing logic here
  let processedData = inputData; 

  // Save the processed data to the destination bucket
  let destParams = {
    Bucket: destinationBucket,
    Key: srcKey,
    Body: processedData
  };

  await s3.putObject(destParams).promise();

};